import{_ as i,o as a,c as e,a0 as o}from"./chunks/framework.CSGB4SNl.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"java/eight-legged essay/java-hot200-day06.md","filePath":"java/eight-legged essay/java-hot200-day06.md"}'),r={name:"java/eight-legged essay/java-hot200-day06.md"};function t(s,l,d,h,n,c){return a(),e("div",null,[...l[0]||(l[0]=[o('<h4 id="mysql如何解决深分页问题" tabindex="-1">mysql如何解决深分页问题 <a class="header-anchor" href="#mysql如何解决深分页问题" aria-label="Permalink to &quot;mysql如何解决深分页问题&quot;">​</a></h4><ol><li>一般情况下如果要查第9999页的，就会先扫描前9999条记录然后再丢弃，这样比较浪费性能</li><li>子查询优化：里面的子查询先查出大于9999的第一条数据的id，这一步直接走索引了比较快，然后父查询就从这一个id开始往后10条20条这样</li><li>游标：每次查询都返回当前页的最大id，下次查询时带上作为条件，大于这个id的分10条数据这样，缺点是没法具体到哪一页，只能连续去翻，且删除数据会导致分页混乱，在第二页时删除第一页数据会被顶回第一页去</li><li>或者限制最大翻页数，因为用户不大可能真的去翻那么多</li></ol><h4 id="redis实现分布式锁会遇到哪些问题" tabindex="-1">redis实现分布式锁会遇到哪些问题 <a class="header-anchor" href="#redis实现分布式锁会遇到哪些问题" aria-label="Permalink to &quot;redis实现分布式锁会遇到哪些问题&quot;">​</a></h4><ol><li>锁过期但是业务没跑完，导致其它线程可以获取到锁，然后原本那个线程执行完就把锁删了，此时B线程拿到锁就被删了</li><li>单机问题，一台redis挂掉后数据就丢失了，整个锁服务就瘫痪了</li><li>多台redis时区问题，导致ttl过期时间会有差异，锁就可能提前释放或者过迟释放</li><li>主从同步延迟: 主节点刚写入锁就挂了，然后新主上来又没有锁，得等其它线程请求进来才有，这个的话可以使用RedLock来解决，就是把锁加到多个redis主节点上面，多数加锁成功才算成功，即使一个挂了其他的还有其它有锁数</li><li>锁不可重入，同一线程再次获取同一锁就又得等待</li></ol><h4 id="工厂模式和抽象工厂模式有什么区别" tabindex="-1">工厂模式和抽象工厂模式有什么区别 <a class="header-anchor" href="#工厂模式和抽象工厂模式有什么区别" aria-label="Permalink to &quot;工厂模式和抽象工厂模式有什么区别&quot;">​</a></h4><ol><li>工厂模式关注的是一个对象，抽象工厂模式关注的是一组有关联的对象</li><li>抽象工厂定义创建多个对象的抽象方法，由具体的工厂子类来实现具体对象，而工厂模式则只针对一种对象创建</li></ol><h4 id="mysql的主从同步机制" tabindex="-1">mysql的主从同步机制 <a class="header-anchor" href="#mysql的主从同步机制" aria-label="Permalink to &quot;mysql的主从同步机制&quot;">​</a></h4><ol><li>过程：主库更新binglog日志后向从库推送更新通知，然后从库读取binglog将数据写入redolog，最后重放到数据库中</li><li>三种同步，区别就是啥时候主库返回响应给客户端，异步写完binglog立即返回，同步等所有从库确认后再返回，半同步等n个从库确认后返回</li><li>两种半同步模式和事务相关:主库先提交事务再等从库确认，缺点是提交后挂了，数据就不一致了，主库等从库确认再提交，好处是挂掉也不会丢</li></ol><h4 id="redisson的原理" tabindex="-1">redisson的原理 <a class="header-anchor" href="#redisson的原理" aria-label="Permalink to &quot;redisson的原理&quot;">​</a></h4><ol><li>本质上是redis-hash + lua脚本保证原子性 + 一个后台线程做看门狗自动续期，且支持可重入，用hash可以记录重入数</li><li>默认锁过期时间是30s，加锁失败后返回通知</li></ol><h4 id="redis如何保证缓存和数据库一致性" tabindex="-1">redis如何保证缓存和数据库一致性 <a class="header-anchor" href="#redis如何保证缓存和数据库一致性" aria-label="Permalink to &quot;redis如何保证缓存和数据库一致性&quot;">​</a></h4><ol><li>先更新缓存再更新数据库：AB两个请求，一个是改10一个是改成20，由于网络波动问题导致缓存先被更新成20，然后数据库最后被更新成10，不一致</li><li>先更新数据库再更新缓存：本质上也是一样的只不过前者数据库先变成20</li><li>先删缓存再更新数据库：因为更新缓存也是得经历一系列计算，不如直接删，还能保证一定的一致性，但是会出现A删完缓存后还没更新到数据库时，B读取没有去数据库拿旧值写入缓存，后数据库又被更新成新值，也有一定的解决方法-延迟双删，第二次删的时间尽量靠近新值写入后-可用定时任务和延迟队列</li><li>先更新数据库再删缓存：问题出在如果缓存恰好过期，此时新值还没写入库，然后读取旧值写入缓存就不一致了，概率比较低</li><li>使用Canel伪装成mysql的从节点，然后订阅Binlog日志的消息，数据库有改就去更新缓存就好,或者消息队列支持重试，但是要维护消息消费顺序，也要有幂等</li></ol><h4 id="tcp三次握手" tabindex="-1">TCP三次握手 <a class="header-anchor" href="#tcp三次握手" aria-label="Permalink to &quot;TCP三次握手&quot;">​</a></h4><ol><li>第一次握手：客户端向服务端发送SYN报文，然后自己初始化一个序列号，并将客户端状态更新成已发送</li><li>第二次握手：服务端收到SYN报文后，回发一个SYN + ACK报文，然后将发来的序列号 + 1生成确认号，然后自己再初始化一个序列号发送，将服务端状态改成已接收</li><li>第三次握手：客户端收到SYN + ACK报文后，发送一个ACK报文，确认号是服务端序列号 + 1，然后将状态改成已建立连接，服务端收到ACK后也改成这个状态，连接就真正建立起来了</li><li>是为了让对方相互知道收发能力正常</li></ol><h4 id="tcp的四次挥手" tabindex="-1">TCP的四次挥手 <a class="header-anchor" href="#tcp的四次挥手" aria-label="Permalink to &quot;TCP的四次挥手&quot;">​</a></h4><ol><li>首先客户端会发送FIN包，表示我不想发了，然后进入到FIN_WAIT_1状态</li><li>然后服务端接收到FIN后表示我知道了，然后发送ACK回应，进入到等待关闭状态</li><li>然后客户端接收到ACK后变成FIN_WAIT_2状态，等到服务端真正发完数据后，服务端发送FIN包表示发完了</li><li>后面客户端接收回应ACK，然后服务端接收到就CLOSE，等待一段时间后客户端也CLOSE</li></ol><h4 id="分布式事务" tabindex="-1">分布式事务 <a class="header-anchor" href="#分布式事务" aria-label="Permalink to &quot;分布式事务&quot;">​</a></h4><ol><li>跨数据库、跨服务时需要用到</li><li>2pc：准备和确认，整个事务分成两个阶段，准备提交和确认提交，会发送准备命令等待所有参与者响应，都准备好就确认提交，否则就发送回滚通知</li><li>3pc：询问、准备、确认，先询问参与者是否可以提交，准备和执行阶段就和2pc一样了</li><li>TTC：会先给所有事务进行try执行，如果其中一个出问题就全部回滚，没问题则全部走提交事务</li><li>消息事务，会将事务发送给消息队列进行，但是这个消息先不对消费者可见，等到消息没问题事务能够执行成功时就可见让消费者消费，如果接收到回滚消息则丢弃原本那个消息</li></ol><h4 id="redis为什么这么快" tabindex="-1">Redis为什么这么快 <a class="header-anchor" href="#redis为什么这么快" aria-label="Permalink to &quot;Redis为什么这么快&quot;">​</a></h4><ol><li>原因：存内存操作 + 单线程 + io多路复用和高效的数据结构</li><li>单线程，一个线程可以监听多个客户端的连接 + 非阻塞式io避免长时间等待造成的资源浪费，且单线程避免了锁的竞争和多线程切换的开销，但是redis的耗时长任务还是会异步执行，像是RDB快照和AOF日志都是后台开个线程异步执行的</li><li>丰富的数据结构如：String、哈希、跳表、列表等</li><li>轻量化协议，不同于HTTP那样复杂，比较紧凑简单</li><li>redis有自己的内存管理器，内存分配回收更高效</li><li>删除大key操作下，耗时其它操作都得等着成为性能瓶颈</li></ol>',20)])])}const u=i(r,[["render",t]]);export{m as __pageData,u as default};
